def gen(rng, size):
    n = max(1, min(size, 10000))
    nums = [rng.randrange(0, 10**9 + 1) for _ in range(n)]
    regime = rng.choice(['zero', 'one', 'mid', 'exact', 'over'])
    if regime == 'zero':
        k = 0
    elif regime == 'one':
        k = 1
    elif regime == 'exact':
        k = n
    elif regime == 'over':
        k = n + rng.randrange(0, 5)
    else:
        k = rng.randrange(2, n) if n >= 3 else 1
    return [nums, k]

