class Solution:
    def maximumTop(self, nums, k):
        n = len(nums)
        if n == 1:
            return -1 if k % 2 == 1 else nums[0]
        if k == 0:
            return nums[0]
        running_max = -1
        for i in range(n):
            if i > k - 2:
                break
            if nums[i] > running_max:
                running_max = nums[i]
        direct = nums[k] if k < n else -1
        return max(running_max, direct)

