class Solution:
    def maximumTop(self, nums, k):
        n = len(nums)
        if n == 1:
            return -1 if k % 2 == 1 else nums[0]
        if k == 0:
            return nums[0]
        best = -1
        if k < n:
            best = nums[k]
        if k >= 2:
            best = max(best, max(nums[:k - 1]))
        return best

