var maximumTop = function(nums, k) {
    const n = nums.length;
    if (n === 1) {
        return (k % 2 === 1) ? -1 : nums[0];
    }
    if (k === 0) return nums[0];
    let best = -1;
    if (k < n) best = nums[k];
    if (k >= 2) {
        const limit = Math.min(k - 1, n);
        for (let i = 0; i < limit; i++) {
            if (nums[i] > best) best = nums[i];
        }
    }
    return best;
};
